const body = $input.first().json.body || $input.first().json;
const msg = body.message || body;
const call = msg.call || {};

const assistantId = call.assistantId || call.assistant?.id || msg.assistantId || msg.assistant?.id || '';
const callId = call.id || msg.callId || '';

// Try all Vapi formats to find the tool call with arguments
let toolName = 'unknown';
let toolParams = {};
let toolCallId = null;

const parseArgs = (args) => {
  if (!args) return {};
  if (typeof args === 'object') return args;
  try { return JSON.parse(args); } catch(e) { return {}; }
};

if (msg.toolWithToolCallList && msg.toolWithToolCallList[0]) {
  const t = msg.toolWithToolCallList[0];
  toolName = t.toolCall?.function?.name || t.function?.name || 'unknown';
  toolParams = parseArgs(t.toolCall?.function?.arguments || t.function?.arguments);
  toolCallId = t.toolCall?.id || t.id || null;
} else if (msg.toolCalls && msg.toolCalls[0]) {
  const t = msg.toolCalls[0];
  toolName = t.function?.name || 'unknown';
  toolParams = parseArgs(t.function?.arguments);
  toolCallId = t.id || null;
} else if (msg.toolCallList && msg.toolCallList[0]) {
  const t = msg.toolCallList[0];
  toolName = t.function?.name || 'unknown';
  toolParams = parseArgs(t.function?.arguments);
  toolCallId = t.id || null;
} else if (msg.functionCall) {
  toolName = msg.functionCall.name || 'unknown';
  toolParams = msg.functionCall.parameters || {};
  toolCallId = null;
}

return [{
  json: {
    assistant_id: assistantId,
    call_id: callId,
    caller_number: call.customer?.number || null,
    tool_name: toolName,
    tool_params: toolParams,
    tool_call_id: toolCallId,
    _debug_tc0: JSON.stringify(msg.toolCalls?.[0] || null),
    _debug_twt0: JSON.stringify(msg.toolWithToolCallList?.[0] || null)
  }
}];

const config = (() => { const r = $input.first().json; return Array.isArray(r) ? r[0] : r; })();
const tool = $('Extract Tool Call').first().json;

if (!config || !config.user_id) {
  return [{ json: { result: 'I apologize, I am unable to process your request at the moment. Please try again or call back later.', user_id: null, should_save: false } }];
}

const toolName = tool.tool_name;
const params = tool.tool_params || {};
const businessName = config.business_name || 'us';

let result = '';
let recordType = 'message';
let should_save = true;

if (toolName === 'book_appointment') {
  const name = params.caller_name || 'the caller';
  const time = params.preferred_time || 'a time to be confirmed';
  const service = params.service_type || 'your appointment';
  result = `Perfect, I've noted down ${service} for ${name} at ${time}. Someone from ${businessName} will confirm this with you shortly. Is there anything else I can help you with?`;
  recordType = 'appointment';
} else if (toolName === 'take_message') {
  const name = params.caller_name || 'the caller';
  result = `Got it, I've taken your message, ${name}. Someone from ${businessName} will get back to you as soon as possible. Is there anything else I can help you with?`;
  recordType = 'message';
} else if (toolName === 'request_callback') {
  const name = params.caller_name || 'the caller';
  result = `Noted! I've logged a callback request for ${name}. Someone from ${businessName} will call you back shortly. Is there anything else I can help you with?`;
  recordType = 'callback';
} else if (toolName === 'check_hours') {
  const hours = config.business_hours;
  if (hours && Object.keys(hours).length > 0) {
    result = `${businessName} business hours are: ${JSON.stringify(hours)}. Is there anything else I can help you with?`;
  } else {
    result = `Please contact ${businessName} directly for their current business hours. Is there anything else I can help you with?`;
  }
  should_save = false;
} else {
  result = `I've noted your request. Someone from ${businessName} will follow up with you shortly.`;
  recordType = 'message';
}

return [{
  json: {
    result,
    user_id: config.user_id,
    business_name: businessName,
    record_type: recordType,
    should_save,
    caller_name: params.caller_name || null,
    caller_number: tool.caller_number || null,
    service_type: params.service_type || null,
    preferred_time: params.preferred_time || null,
    message: params.message || params.reason || null,
    call_id: tool.call_id,
    tool_call_id: tool.tool_call_id
  }
}];
